import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import type { World } from '../../world';
import type { QueryInstance } from '../types';
import { getStore } from '../../trait/trait';
import { $internal } from '../../common';

function matchesPredicate(world: World, entity: Entity, predicate: QueryInstance['predicateModifiers'][number]) {
    const ctx = world[$internal];
    const eid = getEntityId(entity);
    let matchesOrTrait = false;
    const values: any[] = [];
    for (const trait of predicate.traits) {
        const instance = ctx.traitInstances[trait.id];
        if (!instance || !(ctx.entityMasks[instance.generationId]?.[eid] & instance.bitflag)) return false;
        values.push(trait[$internal].get(eid, getStore(world, trait)));
    }
    return !!predicate.predicate(values as never);
}

/**
 * Check if an entity matches a non-tracking query.
 * For tracking queries, use checkQueryTracking instead.
 */
export function checkQuery(world: World, query: QueryInstance, entity: Entity): boolean {
    const staticBitmasks = query.staticBitmasks;
    const generations = query.generations;
    const ctx = world[$internal];
    const eid = getEntityId(entity);

    if (query.traitInstances.all.length === 0) return false;

    for (let i = 0; i < generations.length; i++) {
        const generationId = generations[i];
        const bitmask = staticBitmasks[i];
        if (!bitmask) continue;

        const required = bitmask.required;
        const forbidden = bitmask.forbidden;
        const or = bitmask.or;
        const entityMask = ctx.entityMasks[generationId]?.[eid] || 0;

        if (!forbidden && !required && !or) continue;
        if (forbidden && (entityMask & forbidden) !== 0) return false;
        if (required && (entityMask & required) !== required) return false;
        if (or !== 0) {
            if (entityMask & or) matchesOrTrait = true;
            else if (!query.orPredicateModifiers.length) return false;
        }
    }

    for (const predicate of query.predicateModifiers) if (!matchesPredicate(world, entity, predicate)) return false;
    for (const predicate of query.notPredicateModifiers) if (matchesPredicate(world, entity, predicate)) return false;
    if (query.orPredicateModifiers.length) {
        let matched = false;
        for (const predicate of query.orPredicateModifiers) {
            if (matchesPredicate(world, entity, predicate)) { matched = true; break; }
        }
        if (!matched && !matchesOrTrait) return false;
    }

    return true;
}

